// Recompute HMAC over canonical JSON of each payload, compare to stored
// payload_signature. Counts pass/fail; collects failure details (capped).
const crypto = require('crypto');
const signingKey = $('Vault: Signing Key').first().json.data.data.payload_hmac_key;
if (!signingKey) throw new Error('signing key missing from Vault response');

const rows = $input.all().map(i => i.json);

let verified = 0;
let failed = 0;
const failures = [];

for (const row of rows) {
  // Payloads are stored as JSONB — same canonicalisation rule used at sign
  // time was JSON.stringify with sorted keys.
  let p = row.payload;
  if (typeof p === 'string') {
    try { p = JSON.parse(p); } catch { failures.push({ id: row.id, reason: 'payload not parseable JSON' }); failed++; continue; }
  }
  const canonical = JSON.stringify(p, Object.keys(p).sort());
  const expected = crypto.createHmac('sha256', signingKey).update(canonical).digest('hex');
  // Some pipelines wrote 'hmac-sha256:' prefix; strip if present.
  const stored = String(row.payload_signature).replace(/^hmac-sha256:/, '');
  if (stored === expected) {
    verified++;
  } else {
    failed++;
    if (failures.length < 20) {
      failures.push({ id: row.id, event_type: row.event_type, source: row.source });
    }
  }
}

return [{
  json: {
    sample_size: rows.length,
    verified,
    failed,
    failure_ids: failures.map(f => f.id),
    failures_json: JSON.stringify(failures)
  }
}];
